using System.Text;
using System.Text.Json;
using SplatViz.Core.Analysis;
using SplatViz.Core.Scene;

namespace SplatViz.Core.Export;

public static class ViewerHtmlExporter
{
    private static readonly JsonSerializerOptions Options = new() { WriteIndented = false };

    public static string ToHtml(
        IEnumerable<LayoutPlan> plans,
        IReadOnlyDictionary<string, CoverageReport> reports,
        IReadOnlyDictionary<string, MountabilityReport> mountabilityReports,
        IReadOnlyDictionary<string, IReadOnlyList<SplatabilityCandidate>> splatabilityReports)
    {
        var data = plans.Select(plan => new
        {
            tier = plan.Tier.ToString(),
            name = plan.Name,
            room = new { x = plan.Room.SizeM.X, y = plan.Room.SizeM.Y, z = plan.Room.SizeM.Z },
            volume = new { x = plan.CaptureVolume.CenterM.X, y = plan.CaptureVolume.CenterM.Y, z = plan.CaptureVolume.CenterM.Z, r = plan.CaptureVolume.RadiusM, h = plan.CaptureVolume.HeightM },
            trusses = plan.Trusses.Select(t => new { id = t.Id, ax = t.StartM.X, ay = t.StartM.Y, az = t.StartM.Z, bx = t.EndM.X, by = t.EndM.Y, bz = t.EndM.Z }).ToArray(),
            stands = plan.Stands.Select(s => new { id = s.Id, x = s.BasePositionM.X, y = s.BasePositionM.Y, z = s.BasePositionM.Z, min = s.MinHeightMm, max = s.MaxHeightMm }).ToArray(),
            cameras = plan.Cameras.Select(c => new
            {
                id = c.Id,
                x = System.Math.Round(c.PositionM.X, 4),
                y = System.Math.Round(c.PositionM.Y, 4),
                z = System.Math.Round(c.PositionM.Z, 4),
                ax = c.AimTargetM.X,
                ay = c.AimTargetM.Y,
                az = c.AimTargetM.Z,
                roll = c.PortraitRoll,
                mount = c.Mount.Type,
                mountId = c.Mount.Id,
                pxcm = System.Math.Round(c.ApproxPixelsPerCmAtAim, 2),
                distance = System.Math.Round(c.DistanceToAimM, 3),
                hFov = System.Math.Round(c.HorizontalFovDegrees, 1),
                vFov = System.Math.Round(c.VerticalFovDegrees, 1),
                azimuth = System.Math.Round((System.Math.Atan2(c.PositionM.Y, c.PositionM.X) * 180.0 / System.Math.PI + 360.0) % 360.0, 1),
                elevationTier = c.PositionM.Z > 2.0 ? "high" : "low"
            }).OrderBy(c => c.azimuth).ToArray(),
            report = new
            {
                score = reports[plan.Tier.ToString()].Score,
                coverage = reports[plan.Tier.ToString()].CoveredFraction,
                weak = reports[plan.Tier.ToString()].WeakSectors.Count,
                missing = reports[plan.Tier.ToString()].MissingSectors.Count,
                redundant = reports[plan.Tier.ToString()].RedundantSectors.Count
            },
            mountability = new
            {
                state = mountabilityReports[plan.Tier.ToString()].State,
                unassigned = mountabilityReports[plan.Tier.ToString()].UnassignedCameras,
                issues = mountabilityReports[plan.Tier.ToString()].Issues.Take(8).Select(i => new { severity = i.Severity, cameraId = i.CameraId, mountId = i.MountId, message = i.Message }).ToArray()
            },
            splatability = splatabilityReports[plan.Tier.ToString()].Select(s => new
            {
                resolution = s.ResolutionName,
                width = s.WidthPx,
                height = s.HeightPx,
                distance = s.CameraDistanceM,
                pxcm = s.PixelsPerCm,
                fill = s.BodyFrameHeightPercent,
                bodyMargin = s.BodyMarginScore,
                parallax = s.NeighborParallaxScore,
                dofNear = s.DepthOfFieldNearM,
                dofFar = s.DepthOfFieldFarM,
                dof = s.DepthOfFieldSafetyScore,
                focusPass = s.AcceptableFocusPass,
                criticalNear = s.CriticalSharpnessNearM,
                criticalFar = s.CriticalSharpnessFarM,
                critical = s.CriticalSharpnessScore,
                focusBox = s.FocusBoxConfidenceScore,
                eye = s.EyePlaneConfidenceScore,
                shadow = s.ShadowRiskScore,
                rigLighting = s.RigLightingInterferenceScore,
                splat = s.SplatabilityScore,
                feasibility = s.ProductionFeasibilityScore,
                verdict = s.Verdict,
                notes = s.Notes
            }).ToArray()
        }).ToArray();

        var json = JsonSerializer.Serialize(data, Options).Replace("</", "<\\/");
        var sb = new StringBuilder();
        sb.AppendLine("<!doctype html><html><head><meta charset='utf-8'><title>SplatViz Viewer M1.0-alpha</title>");
        sb.AppendLine("<style>");
        sb.AppendLine("body{margin:0;background:#071014;color:#eef4f1;font-family:Inter,Arial,sans-serif;overflow:hidden}#app{display:grid;grid-template-columns:380px 1fr;height:100vh}.side{background:#0c1519;border-right:1px solid #24343b;padding:20px;box-sizing:border-box;overflow:auto}.label{color:#73b98f;text-transform:uppercase;letter-spacing:.12em;font-size:12px;font-weight:800}h1{font-size:27px;line-height:1.05;margin:10px 0 18px}select,button,input{font-family:inherit}select,button{width:100%;background:#101c20;color:#eef4f1;border:1px solid #2c424a;border-radius:10px;padding:10px;margin:7px 0;font-size:14px}button{cursor:pointer;text-align:left}button.active{border-color:#73b98f;background:#12251c}.stat{background:#081114;border:1px solid #1d3036;border-radius:14px;padding:12px;margin:9px 0}.stat b{font-size:24px;display:block}.stat span{color:#9cb1a8;font-size:12px}.issue{border-left:3px solid #d5a240;padding-left:10px;color:#cddad4;margin:10px 0;font-size:13px;line-height:1.35}.hint{color:#9fb3aa;line-height:1.45;font-size:14px}.stage{position:relative;background:radial-gradient(circle at 50% 35%,#0f1b20,#071014 70%)}canvas{width:100%;height:100%;display:block}.hud{position:absolute;left:24px;bottom:20px;color:#9fb3aa;font-size:13px;background:#081114cc;border:1px solid #24343b;border-radius:12px;padding:12px 14px}.toggles label{display:block;margin:7px 0;color:#c9d9d2}.modeButtons{display:grid;grid-template-columns:1fr;gap:4px;margin:8px 0 12px}.modeButtons button{font-size:12px;padding:7px 9px;margin:0}.modeButtons .active{border-color:#73b98f;background:#12251c}.diagKey{background:#081114;border:1px solid #1d3036;border-radius:12px;padding:10px;margin:8px 0;color:#a9bcb4;font-size:12px;line-height:1.45}.sw{display:inline-block;width:10px;height:10px;border-radius:50%;margin-right:6px}.tabs{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin:12px 0}.cameraList{display:grid;grid-template-columns:1fr 1fr;gap:6px;max-height:144px;overflow:auto;margin:8px 0}.cameraList button{font-size:12px;padding:7px;margin:0}.details,.editor{background:#081114;border:1px solid #1d3036;border-radius:14px;padding:12px;margin-top:10px;font-size:13px;color:#cfe0d8;line-height:1.45}.editor label{display:grid;grid-template-columns:82px 1fr 44px;gap:8px;align-items:center;margin:8px 0}.editor input[type=range]{width:100%;accent-color:#73b98f}.editor input[type=checkbox]{width:auto}.sheet,.compare{position:absolute;inset:0;padding:42px;box-sizing:border-box;overflow:auto;display:none;background:#071014}.sheet h2,.compare h2{font-size:34px;margin:0 0 6px}.sheet p,.compare p{color:#9fb3aa;margin:0 0 22px}.contact{display:grid;grid-template-columns:repeat(6,minmax(150px,1fr));gap:14px}.thumb{background:#0d171b;border:1px solid #24343b;border-radius:16px;overflow:hidden;min-height:184px;cursor:pointer}.thumb.selected{border-color:#73b98f;box-shadow:0 0 0 1px #73b98f55}.thumb.neighbor{border-color:#d5a24066}.render{height:116px;background:linear-gradient(135deg,#102027,#071014);position:relative}.render .body{position:absolute;left:50%;top:18px;width:46px;height:78px;transform:translateX(-50%);border-radius:24px 24px 18px 18px;background:#75b98f66;border:1px solid #93d3aa}.render .axis{position:absolute;left:12px;right:12px;bottom:14px;height:1px;background:#2a464f}.render .viewAngle{position:absolute;right:10px;top:8px;color:#9fb3aa;font-size:11px}.thumbMeta{padding:10px;font-size:12px;color:#a9bcb4}.thumbMeta b{display:block;color:#eef4f1;font-size:15px;margin-bottom:4px}.roll{color:#d5a240}.mounted{color:#73b98f}.unassigned{color:#d5a240}.small{font-size:12px;color:#8fa49b}.exportBox{margin-top:10px}.scorePreview{color:#73b98f}.warningText{color:#d5a240}.grid{display:grid;grid-template-columns:repeat(5,minmax(170px,1fr));gap:14px}.card{background:#0d171b;border:1px solid #24343b;border-radius:16px;padding:14px}.card.safe{border-color:#73b98f}.card.solve_test_recommended{border-color:#d5a240}.card.splat_viable_but_production_risky{border-color:#d66363}.card.not_preferred{border-color:#d66363}.card h3{margin:0 0 8px;font-size:18px}.metric{height:7px;background:#17252b;border-radius:8px;overflow:hidden;margin:5px 0 10px}.metric div{height:100%;background:#73b98f}.metric.warn div{background:#d5a240}.metric.bad div{background:#d66363}.compareTop{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin:12px 0 22px}.compareTop .stat{margin:0}.pill{display:inline-block;border:1px solid #2c424a;border-radius:999px;padding:4px 8px;margin:2px;color:#cfe0d8;font-size:11px}.verdict{font-weight:800;text-transform:uppercase;letter-spacing:.08em;font-size:11px}</style>");
        sb.AppendLine("</head><body><div id='app'><aside class='side'><div class='label'>SplatViz M1.0-alpha viewer</div><h1>Splat Viability Techviz</h1><select id='layout'></select><div class='tabs'><button id='tabScene' class='active'>Scene</button><button id='tabSheet'>Still Sheet</button><button id='tabCompare'>Assessment</button></div><div id='stats'></div><div class='toggles'><label><input type='checkbox' id='frustums' checked> show frustums</label><label><input type='checkbox' id='mounts' checked> show mounts</label><label><input type='checkbox' id='labels' checked> show labels</label></div><div class='label'>frustum view</div><div class='modeButtons'><button id='modeStandard' class='active'>Standard Frustums</button><button id='modeFocus'>Focus Zones</button><button id='modeSplat'>Splat Viability</button></div><div class='diagKey' id='diagKey'><span class='sw' style='background:#73b98f'></span>standard frustum rays</div><div class='label'>cameras</div><div id='cameraList' class='cameraList'></div><div id='cameraDetails' class='details'></div><div id='editor' class='editor'></div><div class='exportBox'><button id='resetCamera'>Reset selected camera</button><button id='exportEdited'>Export edited layout JSON</button></div><p class='hint'>M1.0-alpha adds 3D diagnostic frustum modes: Focus and Splat Viability.</p><div id='issues'></div></aside><main class='stage'><canvas id='c'></canvas><section id='sheet' class='sheet'><h2>Ordered Still Sheet</h2><p>Camera-order contact sheet placeholder. Neighboring cards are highlighted around the selected camera so parallax jumps can be inspected in array order.</p><div id='contact' class='contact'></div></section><section id='compare' class='compare'><h2>Splat Viability Assessment</h2><p>4K / 5K / 6K against camera distance, eye focus, tape-box sharpness, and rig/lighting interference. Final truth comes from exported synthetic stills and a quick gsplat solve.</p><div id='compareTop' class='compareTop'></div><div id='compareGrid' class='grid'></div></section><div class='hud' id='hud'>Drag selected camera. Use Focus or Splat Viability frustum modes for diagnostics.</div></main></div>");
        sb.AppendLine($"<script>const SOURCE_DATA={json};</script>");
        sb.AppendLine(HtmlScript());
        sb.AppendLine("</body></html>");
        return sb.ToString();
    }

    private static string HtmlScript() => """
<script>
const DATA=JSON.parse(JSON.stringify(SOURCE_DATA));
const ORIGINAL=JSON.parse(JSON.stringify(SOURCE_DATA));
let selectedCameraId=null; let activeTab='scene'; let dragging=false; let frustumMode='standard';
const canvas=document.getElementById('c'); const ctx=canvas.getContext('2d');
const sel=document.getElementById('layout'); const stats=document.getElementById('stats'); const issues=document.getElementById('issues');
const cameraList=document.getElementById('cameraList'); const cameraDetails=document.getElementById('cameraDetails'); const editor=document.getElementById('editor');
const sheet=document.getElementById('sheet'); const compare=document.getElementById('compare'); const contact=document.getElementById('contact');
const compareGrid=document.getElementById('compareGrid'); const compareTop=document.getElementById('compareTop'); const hud=document.getElementById('hud'); const diagKey=document.getElementById('diagKey');
for(const d of DATA){const o=document.createElement('option');o.value=d.tier;o.textContent=d.name;sel.appendChild(o);} sel.value='Recommended';
for(const id of ['layout','frustums','mounts','labels']) document.getElementById(id).addEventListener('change',draw);
document.getElementById('tabScene').onclick=()=>{activeTab='scene';draw();};document.getElementById('tabSheet').onclick=()=>{activeTab='sheet';draw();};document.getElementById('tabCompare').onclick=()=>{activeTab='compare';draw();};document.getElementById('modeStandard').onclick=()=>{frustumMode='standard';draw();};document.getElementById('modeFocus').onclick=()=>{frustumMode='focus';draw();};document.getElementById('modeSplat').onclick=()=>{frustumMode='splat';draw();};
document.getElementById('resetCamera').onclick=resetSelectedCamera; document.getElementById('exportEdited').onclick=exportEditedLayout;
window.addEventListener('resize',draw); canvas.addEventListener('pointerdown',onPointerDown); canvas.addEventListener('pointermove',onPointerMove); canvas.addEventListener('pointerup',()=>dragging=false);
function resize(){canvas.width=canvas.clientWidth*devicePixelRatio;canvas.height=canvas.clientHeight*devicePixelRatio;ctx.setTransform(devicePixelRatio,0,0,devicePixelRatio,0,0);} 
function get(){return DATA.find(x=>x.tier===sel.value)||DATA[0];} function getOriginal(){return ORIGINAL.find(x=>x.tier===sel.value)||ORIGINAL[0];}
function selectedCam(d){return d.cameras.find(c=>c.id===selectedCameraId)||d.cameras[0];}
function sortCams(d){d.cameras.sort((a,b)=>azimuth(a)-azimuth(b));} function azimuth(cam){return (Math.atan2(cam.y,cam.x)*180/Math.PI+360)%360;} function distanceXY(cam){return Math.sqrt(cam.x*cam.x+cam.y*cam.y);} 
function setPolar(cam, az, dist){const r=az*Math.PI/180; cam.x=Math.cos(r)*dist; cam.y=Math.sin(r)*dist; cam.azimuth=Math.round(az*10)/10; cam.distance=Math.round(Math.sqrt(cam.x*cam.x+cam.y*cam.y+(cam.z-cam.az)*(cam.z-cam.az))*1000)/1000; cam.pxcm=Math.round((54/(Math.max(2.5,cam.distance))*1.0)*100)/100;}
function iso(x,y,z){const s=Math.min(canvas.clientWidth,canvas.clientHeight)/11; return {x:canvas.clientWidth/2+(x-y)*s*.82,y:canvas.clientHeight*.54+(x+y)*s*.36-z*s*.72,s};}
function inverseIso(px,py,z){const s=Math.min(canvas.clientWidth,canvas.clientHeight)/11; const u=(px-canvas.clientWidth/2)/(s*.82); const v=(py-canvas.clientHeight*.54+z*s*.72)/(s*.36); return {x:(u+v)/2,y:(v-u)/2};}
function line(a,b,color,w=1){ctx.strokeStyle=color;ctx.lineWidth=w;ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.stroke();} function circle(p,r,color,stroke){ctx.fillStyle=color;ctx.beginPath();ctx.arc(p.x,p.y,r,0,Math.PI*2);ctx.fill(); if(stroke){ctx.strokeStyle=stroke;ctx.lineWidth=1.5;ctx.stroke();}} function poly(points,color,stroke){ctx.fillStyle=color;ctx.beginPath();points.forEach((p,i)=>i?ctx.lineTo(p.x,p.y):ctx.moveTo(p.x,p.y));ctx.closePath();ctx.fill();if(stroke){ctx.strokeStyle=stroke;ctx.stroke();}} function mix(a,b,t){return{x:a.x+(b.x-a.x)*t,y:a.y+(b.y-a.y)*t};} function band(center,rx,ry,color,stroke){ctx.fillStyle=color;ctx.beginPath();ctx.ellipse(center.x,center.y,rx,ry,0,0,Math.PI*2);ctx.fill();if(stroke){ctx.strokeStyle=stroke;ctx.lineWidth=1.2;ctx.stroke();}}
function drawRoom(d){const x=d.room.x/2,y=d.room.y/2,z=0;poly([iso(-x,-y,z),iso(x,-y,z),iso(x,y,z),iso(-x,y,z)],'#0d181c','#294149');} function drawVolume(d){const p=iso(d.volume.x,d.volume.y,d.volume.z);circle(p,34,'#70b98e88','#b6dcc5');ctx.strokeStyle='#70b98e';ctx.setLineDash([8,8]);ctx.beginPath();ctx.ellipse(p.x,p.y+8,d.volume.r*55,d.volume.r*22,0,0,Math.PI*2);ctx.stroke();ctx.setLineDash([]);ctx.fillStyle='#e9f3ee';ctx.fillText('performer volume',p.x-44,p.y+64);} function drawMounts(d){if(!document.getElementById('mounts').checked)return;for(const t of d.trusses){line(iso(t.ax,t.ay,t.az),iso(t.bx,t.by,t.bz),'#8bb29e',5);}for(const s of d.stands){line(iso(s.x,s.y,0),iso(s.x,s.y,s.max/1000),'#b89b5e',4);circle(iso(s.x,s.y,0),5,'#b89b5e');}}
function drawFocusDiagnostic(cam,p,a,selected){const c=mix(p,a,1),near=mix(p,a,.72),far=mix(p,a,1.28),accN=mix(p,a,.5),accF=mix(p,a,1.48); if(selected){band(mix(accN,accF,.5),72,24,'#5b789033','#8fb3c7');band(mix(near,far,.5),46,16,'#73b98f44','#9ee0b4');circle(c,5,'#eaf3ef','#eaf3ef');line(p,a,'#78a9bd',2);} else {line(p,a,'#2b4650',1);}} function drawSplatDiagnostic(cam,p,a,selected){const strength=Math.max(0,Math.min(1,(cam.pxcm-8)/6));const color=cam.mount==='unassigned'?'#d5a240':strength>.65?'#73b98f':strength>.35?'#d5a240':'#d66363';line(p,a,color,selected?3.4:1.5);if(selected){band(mix(p,a,.7),34+strength*38,10+strength*12,color+'44',color);}} function setModeButtons(){for(const m of ['Standard','Focus','Splat'])document.getElementById('mode'+m).classList.toggle('active',frustumMode===m.toLowerCase().replace('splat','splat')); diagKey.innerHTML=frustumMode==='focus'?'<span class="sw" style="background:#eaf3ef"></span>focus point / eye plane<br><span class="sw" style="background:#73b98f"></span>critical sharpness zone<br><span class="sw" style="background:#8fb3c7"></span>acceptable focus zone':frustumMode==='splat'?'<span class="sw" style="background:#73b98f"></span>strong projected detail<br><span class="sw" style="background:#d5a240"></span>mount or rig-light risk<br><span class="sw" style="background:#d66363"></span>low projected detail':'<span class="sw" style="background:#73b98f"></span>standard frustum rays';} function drawCameras(d){const showF=document.getElementById('frustums').checked, showL=document.getElementById('labels').checked;setModeButtons();for(const cam of d.cameras){const p=iso(cam.x,cam.y,cam.z),a=iso(cam.ax,cam.ay,cam.az);if(showF){if(frustumMode==='focus')drawFocusDiagnostic(cam,p,a,cam.id===selectedCameraId);else if(frustumMode==='splat')drawSplatDiagnostic(cam,p,a,cam.id===selectedCameraId);else line(p,a,cam.mount==='unassigned'?'#425961':'#2b4650',cam.id===selectedCameraId?2.6:1.2);}circle(p,cam.id===selectedCameraId?12:(cam.roll?8:7),cam.mount==='unassigned'?'#d5a240':'#54bd7e','#eef6f2');if(showL){ctx.fillStyle='#eaf3ef';ctx.font=cam.id===selectedCameraId?'bold 14px Arial':'13px Arial';ctx.fillText(cam.id,p.x+10,p.y+4);}}}
function estimateCoverage(d){sortCams(d); const gaps=[]; for(let i=0;i<d.cameras.length;i++){const a=azimuth(d.cameras[i]); const b=azimuth(d.cameras[(i+1)%d.cameras.length]); gaps.push((b-a+360)%360);} const weak=gaps.filter(g=>g>26&&g<=42).length; const missing=gaps.filter(g=>g>42).length; const tooClose=gaps.filter(g=>g<5).length; const avgGap=gaps.reduce((a,b)=>a+b,0)/gaps.length; const score=Math.max(0,Math.min(100,100-(weak*2.5)-(missing*8)-(tooClose*1.5)-Math.max(0,avgGap-22)*.15)); return {score,weak,missing,tooClose,maxGap:Math.max(...gaps),avgGap};}
function updateSide(d){const live=estimateCoverage(d);stats.innerHTML=`<div class='stat'><b class='scorePreview'>${live.score.toFixed(1)}</b><span>live score preview</span></div><div class='stat'><b>${(d.report.coverage*100).toFixed(0)}%</b><span>baseline coverage</span></div><div class='stat'><b>${d.cameras.length}</b><span>cameras</span></div><div class='stat'><b>${d.mountability.unassigned}</b><span>unassigned mounts</span></div><div class='stat'><b>${live.maxGap.toFixed(1)}°</b><span>max angular gap</span></div>`;issues.innerHTML='<div class="label">mountability</div>'+ (d.mountability.issues.length?d.mountability.issues.map(i=>`<div class="issue"><b>${i.cameraId}</b> · ${i.mountId}<br>${i.message}</div>`).join(''):'<p class="hint">No mountability issues in the visible summary.</p>');}
function updateCameraList(d){sortCams(d);if(!selectedCameraId)selectedCameraId=d.cameras[0]?.id;cameraList.innerHTML=d.cameras.map(cam=>`<button class='${cam.id===selectedCameraId?'active':''}' data-cam='${cam.id}'>${cam.id} · ${Math.round(azimuth(cam))}°</button>`).join('');cameraList.querySelectorAll('button').forEach(b=>b.addEventListener('click',()=>{selectedCameraId=b.dataset.cam;draw();}));updateCameraDetails(d);updateEditor(d);} function neighborIds(d, cam){const idx=d.cameras.findIndex(c=>c.id===cam.id); if(idx<0)return []; return [d.cameras[(idx-1+d.cameras.length)%d.cameras.length].id,d.cameras[(idx+1)%d.cameras.length].id];}
function updateCameraDetails(d){const cam=selectedCam(d); if(!cam){cameraDetails.innerHTML='No camera selected.';return;} const neighbors=neighborIds(d,cam); cameraDetails.innerHTML=`<b>${cam.id}</b><br>azimuth ${azimuth(cam).toFixed(1)}° · ${cam.elevationTier} tier<br>${cam.roll?'portrait roll':'landscape'} · ${cam.mount}<br>${distanceXY(cam).toFixed(2)} m radius · ${cam.z.toFixed(2)} m high<br>${cam.distance} m to aim · ${cam.pxcm} px/cm<br><span class='small'>neighbors: ${neighbors.join(' / ')} · mount: ${cam.mountId}</span>`;}
function updateEditor(d){const cam=selectedCam(d); if(!cam){editor.innerHTML='';return;} editor.innerHTML=`<div class='label'>edit selected camera</div><label>azimuth <input id='editAz' type='range' min='0' max='359' step='1' value='${azimuth(cam).toFixed(0)}'><span id='azVal'>${azimuth(cam).toFixed(0)}°</span></label><label>distance <input id='editDist' type='range' min='2.5' max='6.5' step='0.1' value='${distanceXY(cam).toFixed(1)}'><span id='distVal'>${distanceXY(cam).toFixed(1)}m</span></label><label>height <input id='editHeight' type='range' min='0.8' max='3.4' step='0.05' value='${cam.z.toFixed(2)}'><span id='heightVal'>${cam.z.toFixed(2)}m</span></label><label>roll <span><input id='editRoll' type='checkbox' ${cam.roll?'checked':''}> portrait</span><span></span></label><div class='small warningText'>Live score is a fast browser preview. Core re-score happens on export/build.</div>`; const az=document.getElementById('editAz'),dist=document.getElementById('editDist'),height=document.getElementById('editHeight'),roll=document.getElementById('editRoll'); function apply(){setPolar(cam,Number(az.value),Number(dist.value));cam.z=Number(height.value);cam.roll=roll.checked;cam.elevationTier=cam.z>2?'high':'low';draw();} az.oninput=apply;dist.oninput=apply;height.oninput=apply;roll.onchange=apply;}
function updateSheet(d){sortCams(d); const cam=selectedCam(d); const neighbors=cam?neighborIds(d,cam):[]; contact.innerHTML=d.cameras.map(c=>`<article class='thumb ${c.id===selectedCameraId?'selected':neighbors.includes(c.id)?'neighbor':''}' data-cam='${c.id}'><div class='render'><div class='body'></div><div class='axis'></div><div class='viewAngle'>${Math.round(azimuth(c))}°</div></div><div class='thumbMeta'><b>${c.id} · ${azimuth(c).toFixed(1)}°</b><span class='${c.roll?'roll':''}'>${c.roll?'portrait roll':'landscape'}</span><br><span class='${c.mount==='unassigned'?'unassigned':'mounted'}'>${c.mount}</span> · ${c.elevationTier}<br>${c.pxcm} px/cm · ${c.hFov}° hFOV</div></article>`).join('');contact.querySelectorAll('.thumb').forEach(el=>el.addEventListener('click',()=>{selectedCameraId=el.dataset.cam;activeTab='scene';draw();}));}
function bar(v){const cls=v<60?'bad':v<75?'warn':''; return `<div class='metric ${cls}'><div style='width:${Math.max(0,Math.min(100,v))}%'></div></div>`;} function verdictClass(v){return ['safe','solve_test_recommended','splat_viable_but_production_risky'].includes(v)?v:'not_preferred';}
function updateComparator(d){const sorted=[...d.splatability].sort((a,b)=>(b.splat+b.feasibility*.35)-(a.splat+a.feasibility*.35)); const best=sorted[0]; const low=sorted.find(x=>x.resolution.startsWith('4K')&&(x.verdict==='safe'||x.verdict==='solve_test_recommended'||x.verdict==='splat_viable_but_production_risky')); const five=sorted.find(x=>x.resolution.startsWith('5K')&&(x.verdict==='safe'||x.verdict==='solve_test_recommended')); compareTop.innerHTML=`<div class='stat'><b>${best.resolution}</b><span>best predicted · ${best.distance}m · ${best.verdict.replaceAll('_',' ')}</span></div><div class='stat'><b>${five?five.distance+'m':'—'}</b><span>5K challenger</span></div><div class='stat'><b>${low?low.distance+'m':'—'}</b><span>lowest 4K solve-test candidate</span></div>`; compareGrid.innerHTML=sorted.map(c=>`<article class='card ${verdictClass(c.verdict)}'><h3>${c.resolution} · ${c.distance}m</h3><div class='verdict'>${c.verdict.replaceAll('_',' ')}</div><div class='small'>${c.width}×${c.height} · ${c.pxcm} px/cm · body ${c.fill}% frame height</div><div class='small'>Splat Viability score ${c.splat}</div>${bar(c.splat)}<div class='small'>Production feasibility ${c.feasibility}</div>${bar(c.feasibility)}<div class='small'>Focus Box ${c.focusBox} · Critical ${c.critical} · Eye ${c.eye}</div>${bar(c.focusBox)}<div class='small'>Parallax ${c.parallax} · Rig/light safety ${c.rigLighting}</div><div>${(c.notes||[]).slice(0,4).map(n=>`<span class='pill'>${n}</span>`).join('')}</div></article>`).join('');}
function setTabs(){for(const id of ['Scene','Sheet','Compare'])document.getElementById('tab'+id).classList.toggle('active',activeTab===id.toLowerCase().replace('compare','compare').replace('sheet','sheet'));sheet.style.display=activeTab==='sheet'?'block':'none';compare.style.display=activeTab==='compare'?'block':'none';canvas.style.display=activeTab==='scene'?'block':'none';hud.textContent=activeTab==='scene'?'Drag selected camera. Use sliders for precise edits.':activeTab==='sheet'?'Still Sheet cards are linked to Scene View selection.':'Splat Viability Assessment predicts capture risk; gsplat solve remains the verification step.';}
function onPointerDown(e){if(activeTab!=='scene')return; const d=get(); const cam=selectedCam(d); if(!cam)return; const p=iso(cam.x,cam.y,cam.z); const rect=canvas.getBoundingClientRect(); const x=e.clientX-rect.left,y=e.clientY-rect.top; if(Math.hypot(x-p.x,y-p.y)<28){dragging=true; canvas.setPointerCapture?.(e.pointerId);}} function onPointerMove(e){if(!dragging||activeTab!=='scene')return; const d=get(); const cam=selectedCam(d); const rect=canvas.getBoundingClientRect(); const p=inverseIso(e.clientX-rect.left,e.clientY-rect.top,cam.z); cam.x=p.x; cam.y=p.y; cam.azimuth=Math.round(azimuth(cam)*10)/10; cam.distance=Math.round(Math.sqrt(cam.x*cam.x+cam.y*cam.y+(cam.z-cam.az)*(cam.z-cam.az))*1000)/1000; draw();}
function resetSelectedCamera(){const d=get(), orig=getOriginal(), cam=selectedCam(d); if(!cam)return; const o=orig.cameras.find(c=>c.id===cam.id); if(!o)return; Object.assign(cam,JSON.parse(JSON.stringify(o))); draw();}
function exportEditedLayout(){const d=get(); const live=estimateCoverage(d); const payload={splatviz_version:'1.0.0-alpha',export_type:'edited_viewer_layout',layout:d.name,tier:d.tier,live_score_preview:Number(live.score.toFixed(3)),max_gap_degrees:Number(live.maxGap.toFixed(3)),splat_viability_note:'Run core Splat Viability Assessment and quick gsplat solve after export.',cameras:d.cameras.map(c=>({id:c.id,x_m:c.x,y_m:c.y,z_m:c.z,azimuth_deg:Number(azimuth(c).toFixed(3)),distance_m:Number(distanceXY(c).toFixed(3)),portrait_roll:c.roll,mount:c.mount,mount_id:c.mountId}))}; const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=`splatviz_${d.tier.toLowerCase()}_edited_layout.json`; a.click(); URL.revokeObjectURL(a.href);}
function draw(){resize();const d=get();if(!selectedCameraId||!d.cameras.some(c=>c.id===selectedCameraId))selectedCameraId=d.cameras[0]?.id;setTabs();updateSide(d);updateCameraList(d);updateSheet(d);updateComparator(d);ctx.clearRect(0,0,canvas.clientWidth,canvas.clientHeight);if(activeTab==='scene'){drawRoom(d);drawMounts(d);drawVolume(d);drawCameras(d);}}
draw();
</script>
""";
}
